INSERT INTO `news` VALUES (5, 'Lưu ý khi nhập cảnh vào Malaysia', 'Từ ngày 01/05/2024, Cục nhập cư Malaysia yêu cầu tất cả các hành khách quốc tịch nước ngoài (bao gồm quốc tịch Việt Nam) phải đăng ký Thẻ nhập cảnh kỹ thuật số Malaysia (MDAC - Malaysia Digital Arrival Card) trong vòng 03 ngày trước khi nhập cảnh Malaysia, ngoại trừ: \r\n\r\n- Hành khách quá cảnh (transit/transfer) qua Singapore mà không làm thủ tục nhập cảnh; Và Thường trú nhân Malaysia (Malaysia Permanent Resident) \r\n- Những người nhập cảnh bằng hệ thống thông quan tự động (Malaysia Automated Clearance System - MACS) \r\n- Trường hợp hành khách không có Smartphone để xuất trình mã QR tại sân bay thì sau khi đăng ký xong cần in mã QR ra cầm trên tay để xuất trình khi làm thủ tục tại quầy. \r\n*Link thông tin chi tiết vui lòng xem tại: https://imigresen-online.imi.gov.my/mdac/main \r\n\r\n*Link đăng ký MDAC: https://imigresen-online.imi.gov.my/mdac/main?registerMain ', 'https://res.cloudinary.com/dzk9xaroz/image/upload/v1744952079/news/coauxrmaw6v31kammyzo.jpg', '2025-05-03 10:11:49');
INSERT INTO `news` VALUES (6, 'Thông báo thay đổi hình thức Khai báo Nhập cảnh vào Thái Lan', 'Kể từ ngày 01/03/2025, tất cả hành khách là người nước ngoài nhập cảnh vào Thái Lan sẽ thực hiện khai báo nhập cảnh Kỹ Thuật Số (TDAC) thay cho việc khai báo bằng giấy. \r\n\r\nQuý khách được yêu cầu hoàn thành mẫu trực tuyến TDAC, trong đó bao gồm thông tin nhập cảnh và khai báo sức khỏe theo quy định của Bộ Y tế Thái Lan. Truy cập tờ khai tại http://tdac.immigration.go.th.\r\nLuật nhập cảnh vào Thái Lan: \r\n- Mọi hành khách phải hoàn thành thẻ xác nhận nhập cảnh kỹ thuật số của Thái trước khi nhập cảnh. \r\n- Người nước ngoài lưu trú quá 90 ngày tại Thái Lan phải thông báo bằng văn bản cho Cán bộ Nhập Cảnh gần nơi cư trú ngay khi hết hạn 90 ngày và sau đó thực hiện mỗi 90 ngày. \r\n- Người nước ngoài không được phép làm việc nếu không có Giấy phép Lao động. \r\n\r\nCác trường hợp hành khách không phải thực hiện khai báo nhập cảnh   \r\n\r\n* Khách quá cảnh hoặc chuyển máy bay không qua kiểm soát nhập cảnh. \r\n* khách nước ngoài nhập cảnh Thái Lan bằng qua biên giới \r\n', 'https://storage.googleapis.com/airline-tickets-52c6e.firebasestorage.app/users/Thông báo thay đổi hình thức Khai báo Nhập cảnh vào Thái Lan/c2efa390-6a8b-43a2-821f-22f015fb7a13_u11716168231512-1743480568661.jpg', '2025-05-03 10:11:49');
INSERT INTO `news` VALUES (7, 'Khuyến cáo di chuyển dành cho hành khách tới Bali - Indonesia', 'Thực hiện thu phí đối với khách du lịch quốc tế áp dụng từ ngày 14/02/2024. \r\n\r\n1. Mục đích thu phí: Phí du lịch quốc tế sẽ được sử dụng cho việc bảo tồn văn hóa và quản lý chất thải tại Bali. \r\n2. Mức phí yêu cầu: Rp 150,000 / 01 hành khách \r\n3. Hình thức thanh toán:\r\n+ Khách du lịch quốc tế được khuyến cáo nên thanh toán trực tuyến trước khi khởi hành đến Bali thông qua đường link https://lovebali.baliprov.go.id/. \r\n+ Chứng nhận thanh toán dưới dạng mã QR từ hệ thống Love Bali sẽ được gửi qua mail tới hành khách.\r\n4. Các bước thực hiện: tham khảo tài liệu đính kèm và làm theo hướng dẫn.\r\n5. Các trường hợp được miễn Phí du lịch quốc tế:\r\na. Người có thị thực ngoại giao và công vụ.\r\nb. Thuyền viên, Phi hành đoàn.\r\nc. Người có Thẻ tạm trú (KITAS) hoặc Thẻ lưu trú vĩnh viễn (KITAP).\r\nd. Người có thị thực đoàn tụ gia đình.\r\ne. Du học sinh.\r\nf. Người có thị thực loại vàng.\r\ng. Và người có các loại thị thực khác \r\n* Để được miễn nộp phí, khách du lịch quốc tế phải nộp đơn đăng ký thông qua hệ thống Love Bali ít nhất 05 ngày trước khi nhập cảnh vào Bali.', 'https://storage.googleapis.com/airline-tickets-52c6e.firebasestorage.app/users/Khuyến cáo di chuyển dành cho hành khách tới Bali - Indonesia/e665f568-184e-41bb-9817-1d34a0e12b47_vietjetcabincrew1701917453265-1705641046509.jpg', '2025-05-03 10:11:49');
INSERT INTO `news` VALUES (8, 'Lưu ý hành trình bay đến Perth/Adelaide Úc', '1. Hành trình từ TP Hồ Chí Minh (SGN) đến Perth (PER) - Adelaide (ADL), Chuyến bay sẽ tạm dừng tại Perth (PER) sau đó tiếp tục hành trình đến Adelaide (ADL).\r\n\r\n- Quý khách có hành trình từ TP Hồ Chí Minh (SGN) đến Perth (PER): Khi làm thủ tục tại SGN, Quý khách sẽ nhận thẻ lên máy bay và thẻ hành lý đến PER (nếu có ký gửi hành lý). Khi máy bay đáp tại PER, Quý khách vui lòng chuẩn bị sẵn thẻ lên máy bay và hộ chiếu để tiện đối chiếu khi rời khỏi máy bay, sau đó sẽ làm thủ tục nhập cảnh và nhận lại hành lý ký gửi (nếu có).\r\nLưu ý: Hãng sẽ không giải quyết trường hợp hành khách không xuống máy bay tại PER mà yêu cầu đi tiếp ADL.\r\n\r\n- Quý khách có hành trình từ Hồ Chí Minh (SGN) đến Adelade (ADL): Khi làm thủ tục tại SGN, Quý khách sẽ nhận được thẻ lên máy bay và thẻ hành lý đến ADL (nếu có ký gửi hành lý). Khi máy bay đáp tại PER (điểm tạm dừng), hành khách sẽ ngồi lại trên máy bay chờ cho hành khách đến PER xuống máy bay, sau đó sẽ tiếp tục hành trình đến ADL.\r\nLưu ý: Hãng sẽ không giải quyết trường hợp hành khách xuống máy bay tại PER.\r\n \r\n\r\n2. Hành trình từ Adelaide (ADL) - Perth (PER) đến TP Hồ Chí Minh (SGN), Chuyến bay sẽ tạm dừng tại Perth (PER) sau đó tiếp tục hành trình đến Tp. Hồ Chí Minh (SGN).\r\n\r\n- Quý khách có hành trình từ Adelaide (ADL) đến Tp. Hồ Chí Minh (SGN): Khi làm thủ tục tại ADL, Quý khách sẽ nhận được thẻ lên máy bay và thẻ hành lý đến SGN (nếu có ký gửi hành lý). Khi máy bay đáp tại PER, Quý khách vui lòng ngồi lại trên máy bay, chờ hành khách có hành trình từ PER đi SGN lên máy bay ổn định chỗ ngồi và sau đó sẽ tiếp tục hành trình đến SGN.\r\nLưu ý: Hãng không giải quyết trường hợp khách từ ADL đến Tp. Hồ Chí Minh (SGN) nhưng lại yêu cầu xuống tại Perth (PER).\r\n\r\n- Quý khách có hành trình từ Perth (PER) đến Tp. Hồ Chí Minh (SGN): Khi làm thủ tục tại PER, Quý khách sẽ nhận thẻ lên máy bay và thẻ hành lý ký gửi đến SGN (nếu có ký gửi hành lý), trên chuyến bay sẽ có khách từ Adelaide (ADL) đến SGN bay cùng Quý khách. Khi máy bay đáp tại SGN, tất cả hành khách sẽ xuống máy bay, làm thủ tục nhập cảnh và nhận lại hành lý ký gửi (nếu có) và hoàn tất chuyến bay.\r\nChúc quý khách một chuyến bay tốt đẹp cùng Vietjet.', 'https://storage.googleapis.com/airline-tickets-52c6e.firebasestorage.app/users/Lưu ý hành trình bay đến Perth/Adelaide Úc/2a9abca6-31a8-449d-8cc5-3ef8f32abefd_vietjet-aircraft-1670694369152.jpg', '2025-05-03 10:11:49');
INSERT INTO `news` VALUES (9, 'Khuyến cáo di chuyển trên các chuyến bay đi Úc', '1. Quy định hải quan:\r\n- Các loại loại áo quần hay mũ gắn lông chim, hoặc đan bằng tre nứa, cọ lát… tất cả đều bị cấm và sẽ bị tịch thu ngay từ sân bay. - Nếu cố tình giấu giếm, rất có thể sẽ phải chịu phạt tùy mức độ nghiêm trọng khi bị phát hiện.\r\n- Động vật hoang dã hay những chế phẩm làm từ những loại động vật được bảo vệ. Đồng thời cũng cấm mang ra khỏi đất nước Australia những động vật và thực vật, những chế phẩm có nguồn gốc từ thế giới hoang dã (san hô, vỏ ốc, bò sát...) nếu không có giấy phép của cấp có thẩm quyền.\r\nTham khảo: List of prohibited items (abf.gov.au)\r\n- Các loại thực phẩm tươi sống hoặc đã chế biến như đồ hộp, trái cây, rau, trứng, sữa, thịt, gia vị, ngũ cốc, thực vật, hoa, gỗ, hạt giống, và các sản phẩm từ động vật như da thú và lông thú đều bị cấm khi nhập cảnh Úc.\r\n- Úc rất gắt gao trong các trường hợp du khách mang theo đồ ăn, thực phẩm, thuốc men… và quy trình xét duyệt rất phức tạp. Cần khai báo với Hải Quan Úc, và phải qua quá trình kiểm xét nghiệm thực phẩm mới có thể lấy hành lý và chính thức được nhập cảnh. Nếu có mang theo mà không khai báo, hoặc khai báo không trung thực, hành khách có thể bị phạt, thị thực có thể sẽ bị huỷ bỏ và bị từ chối nhập cảnh hoặc có thể bị truy tố trước pháp luật.\r\nTham khảo: Prohibited goods (abf.gov.au)\r\n\r\n2. Thời tiết:\r\n- Vì nằm ở Nam Bán Cầu nên thời tiết tại Úc sẽ ngược so với những đất nước ở Bắc Bán Cầu. Gần 1/3 nước Úc là khí hậu nhiệt đới với 4 mùa (Mùa hè từ tháng 12 đến tháng 2; Mùa thu từ tháng 3 đến tháng 5; Mùa đông từ tháng 6 đến tháng 8; Mùa xuân là từ tháng 9 đến tháng 11) và phần còn lại là khu vực khí hậu ôn đới. Thời tiết các bang có sự khác nhau rõ rệt trong cùng mùa, trong đó thời tiết ở Melbourne khá thất thường, khoảng cách nhiệt độ trong ngày ở Melbourne rất lớn, chênh lệch khoảng 20 độ.\r\n- Nhiệt độ mùa hè ở Úc rất cao, có thể lên tới 40 độ. Do đó, luôn kiểm tra thời tiết trước chuyến đi để đảm bảo chuẩn bị trang phục đầy đủ và phù hợp.\r\n3. Trang thiết bị điện tử mang theo:\r\n\r\n- Úc sử dụng dòng điện có hiệu điện thế 220 - 240V, AC 50Hz. Hầu hết các thiết bị điện tử mới (bao gồm bộ sạc điện thoại và máy tính xách tay) có dải điện áp đầu vào trong khoảng từ 100 - 240v đến 50-60hz.\r\n- Úc sử dụng ổ cắm điện ba chấu chân dẹt khác với Việt Nam, quý khách lưu ý mang theo cục biến thế hoặc bộ chuyển đổi (Adapter) nếu thiết bị điện sử dụng điện thế khác với điện thế ở Úc.', 'https://storage.googleapis.com/airline-tickets-52c6e.firebasestorage.app/users/news/e1c7c566-a635-4c1d-8f07-d86ea4811120_calebrusselljmuyblibrounsplash-large-1679892695174.jpeg', '2025-05-03 10:11:49');
INSERT INTO `news` VALUES (11, 'Quy định về hành lý', 'I/ Quy định về Hành lý xách tay:\r\n\r\nHành lý xách tay đúng quy định được phép mang lên tàu bay phải đáp ứng các điều kiện sau:\r\n\r\n1. Điều kiện về trọng lượng:\r\nMỗi hành khách (ngoại trừ em bé dưới 2 tuổi) được phép mang 01 kiện hành lý xách tay chính và/hoặc 01 túi xách nhỏ với tổng trọng lượng hành lý xách tay không vượt quá 07kg (tùy theo điều kiện hạng vé và đường bay). \r\n\r\n2. Điều kiện về kích thước:\r\n01 kiện hành lý xách tay chính có kích thước tối đa 56cm x 36cm x 23cm.\r\n01 túi cá nhân nhỏ (gồm một trong những túi sau):\r\n01 túi xách phụ nữ hoặc sách, tạp chí, máy ảnh, túi đựng thức ăn cho em bé, túi mua hàng tại sân bay...có kích thước không quá 30cm x 20cm x 10cm.\r\n01 túi đựng áo khoác có kích thước tối đa khi mở ra không quá 114cm x 60cm x 11cm.\r\n01 túi đựng máy tính xách tay có khích thước tối đa là 40cm x 30cm x 10cm.\r\n3. Điều kiện về nhãn hành lý xách tay:\r\nHành lý xách tay phải được dán nhãn hành lý xách tay của Vietjet. Quý Hành Khách vui lòng liên hệ nhân viên Vietjet để dán nhãn cho hành lý xách tay theo quy định của hãng tại quầy Check-in. Tất cả hành lý xách tay không dán “nhãn hành lý xách tay” sẽ bị từ chối mang lên tàu bay.\r\n\r\n4. Điều kiện về quy định chất lỏng hành lý xách tay\r\nTùy thuộc vào luật áp dụng và quy định tại chỗ, hành khách được mang chất lỏng trong hành lý xách tay lên máy bay, nếu hành lý đó đáp ứng các điều kiện sau:\r\n\r\na) Chất lỏng được đựng trong vật chứa với thể tích không quá 100ml;\r\n\r\nb) Tất cả các vật chứa chất lỏng có thể tích tối đa 100ml mỗi thứ có thể được dễ dàng tách riêng vào một túi bóng trong suốt có thể đóng kín có thể tích 1 lít.\r\n\r\nc) Túi nhựa có thể phải được mở riêng ra ở khu vực an ninh. Quý khách có thể sẽ bị đòi hỏi phải bỏ đi các chất lỏng nếu không đáp ứng các yêu cầu trên.\r\n\r\n(*) Lưu ý quan trọng:\r\n\r\nHành lý xách tay mang lên máy bay phải đúng quy định về hành lý xách tay của Vietjet và phải đặt vừa vào dưới chỗ ngồi trước mặt quý khách hoặc ngăn hành lý trong khoang hành khách. Các kiện hành lý mà chúng tôi xác định là có trọng lượng hoặc kích thước vượt quá quy định cho phép sẽ không được phép mang lên tàu bay.\r\nChúng tôi có quyền kiểm tra lại trọng lượng và kích thước hành lý xách tay của quý khách tại cửa khởi hành. Hành lý xách tay không đúng quy định, quý khách sẽ phải trả phí để ký gửi hành lý hoặc hành lý của quý khách sẽ bị từ chối chuyên chở.\r\nPhí gửi hành lý sẽ cao hơn ở khu vực làm thủ tục và ở cửa khởi hành. Phí sẽ được thu bằng đơn vị tiền tệ nước sở tại. Hãy đảm bảo mua trước hành lý để tiết kiệm hơn.\r\nVui lòng tham khảo phí gửi hành lý của Vietjet tại đây. >>>\r\n \r\n\r\nII/ Quy định về Hành lý ký gửi:\r\n\r\n \r\n\r\n1. Hành lý ký gửi tiêu chuẩn\r\n\r\nTrọng lượng Hành lý ký gửi tiêu chuẩn không quá 32kg/ 1 kiện\r\nKích thước không quá: 119cm x 119cm x 81cm.\r\nBộ dụng cụ chơi Golf với tổng kích thước (dài + rộng + cao) không vượt qua 203 cm sẽ được tính là Hành ký gửi tiêu chuẩn.\r\nQuý khách đăng ký trả trước dịch vụ Hành lý ký gửi tại Website, Phòng vé, Đại lý và Trung Tâm phục vụ khách hàng của chúng tôi. Phí dịch vụ Hành lý ký gửi sẽ cao hơn khi mua tại sân bay.\r\n\r\n \r\n\r\n2. Hành lý ký gửi quá khổ (Dịch vụ áp dụng từ ngày 03/01/2020)\r\n\r\nDịch vụ chỉ áp dụng trên chuyến bay Vietjet (VJ)\r\n\r\nTrọng lượng Hành lý ký gửi quá khổ không quá 32 kg/ 1 kiện\r\nKích thước quá quy định của hành lý ký gửi tiêu chuẩn nhưng không quá : 200cm x 119cm x 81 cm\r\nGói Hành lý ký gửi quá khổ được mua trước đã gồm phí Hành lý ký gửi và phí dịch vụ xử lý Hành lý quá khổ.\r\nQuý khách đăng ký mua trước Gói Hành lý quá khổ tại Website, Phòng vé, Đại lý và Trung Tâm phục vụ khách hàng của chúng tôi.\r\n(*) Lưu ý:\r\n\r\nHành khách đặt mua trước gói Hành lý quá khổ được ký gửi hành lý tương ứng trọng lượng gói đã mua, trong đó bao gồm 1 kiện quá khổ/ khách/ chặng bay.\r\nQuý khách vẫn có thể ký gửi thêm hành lý tiêu chuẩn trong trường hợp gói hành lý quá khổ đã mua còn dư trọng lượng sau khi ký gửi kiện hành lý quá khổ.\r\n(Ví dụ: Quý khách đặt mua gói Hành lý quá khổ 30kg, trong đó Quý khách có thể gửi 1 kiện quá khổ 25kg + 1 gói hành lý tiêu chuẩn 5kg).\r\n\r\nTừ kiện Hành lý quá khổ thứ 2 phát sinh, Quý khách sẽ phải mua bổ sung dịch vụ tại sân bay, và tuân theo quy định 2 kiện quá khổ/ khách/ chặng bay. Tuy nhiên việc phục vụ có thể được điều chỉnh cho phù hợp theo thực tế khai thác tại sân bay.\r\nHành khách đã mua gói Hành lý ký gửi tiêu chuẩn vẫn có thể thay đổi thành Hành lý quá khổ trước 3 tiếng so với giờ bay khởi hành dự kiến bằng cách liên hệ các kênh bán để yêu cầu. Phí dịch vụ Hành lý quá khổ sẽ cao hơn khi mua tại sân bay.\r\nVui lòng tham khảo phí gửi hành lý của Vietjet tại đây. >>>\r\n\r\n3. Điều kiện chung của Hành lý ký gửi\r\n- Các vật phẩm không được chấp nhận dưới dạng Hành lý ký gửi hoặc vận chuyển trong hành lý, chúng tôi có quyền từ chối vận chuyển hành lý hoặc vật phẩm trong hành lý như sau:\r\n\r\n \r\n\r\na. Các vật phẩm không được đóng gói đúng quy cách, không đủ điều kiện vận chuyển an toàn với sự chăm sóc và xử lý thông thường.\r\n\r\nb. Các vật phẩm có thể gây nguy hại cho tàu bay hoặc người hoặc tài sản trên tàu bay, như các loại vật phẩm quy định trong các quy định về Hàng hóa Nguy hiểm của tổ chức hàng không thế giới (ICAO) và Hiệp hội vận tải hàng không thế giới (IATA) và trong Điều lệ vận chuyển và Các điều khoản hợp đồng của chúng tôi.\r\n\r\nc. Các vật phẩm bị cấm theo quy định của luật áp dụng, quy định hoặc lệnh của bất kỳ bang hay quốc gia nào nơi bay đến, bay đi và bay qua.\r\n\r\nd. Các vật phẩm theo nhận định của chúng tôi là không thích hợp cho việc vận chuyển do trọng lượng, hình dáng, kích thước hoặc tính chất của chúng.\r\n\r\ne. Các vật phẩm dễ vỡ hoặc dễ hỏng.\r\n\r\nf. Động vật sống hoặc chết.\r\n\r\ng. Hài cốt hoặc động vật.\r\n\r\nh. Hải sản tươi sống hoặc đông lạnh hoặc các loại thịt, với điều kiện các vật phẩm này có thể vận chuyển dưới dạng hành lý xách tay nếu chúng tôi chấp thuận rằng chúng đã được đóng gói đúng quy cách. Chỉ những thùng xốp và/hoặc thùng giữ lạnh chứa đựng thực phẩm khô/không bị hư hỏng có thể được phép làm thủ tục sau khi các cơ quan chức năng đã kiểm tra nội dung bên trong. Nếu Hành khách từ chối việc kiểm tra, thì chúng tôi có quyền từ chối vận chuyển Hành lý.\r\n\r\ni. Súng và đạn dược.\r\n\r\nj. Chất nổ, khí gas dễ cháy hoặc không cháy (như bình xịt phun sơn, khí butan, gas nạp hộp quẹt), khí làm lạnh (như bình dưỡng khí dưới nước, nitơ lỏng), chất lỏng dễ cháy (như sơn, chất pha loãng, dung môi); chất rắn dễ cháy (như diêm, bật lửa); hợp chất oxy hữu cơ (như nhựa cây); chất độc, chất lây nhiễm (như virut, vi khuẩn); chất phóng xạ (như Ra-đi); chất ăn mòn (như axit, kiềm, thủy ngân, nhiệt kế), chất có từ tính, vật liệu oxy hóa (như chất tẩy trắng).\r\n\r\nk. Vũ khí như súng, kiếm, dao cổ và các vật phẩm tương tự, với điều kiện các vật phẩm đó có thể được phép vận chuyển dưới dạng hành lý ký gửi hoàn toàn theo quyết định của chúng tôi vì những lý do rất đặc biệt. Những thứ này không được phép mang lên máy bay vì bất kỳ lý do gì.\r\n\r\nHàng hóa có giá trị và dễ vỡ: Hành khách được khuyến cáo không ký gửi các vật phẩm này trong hành lý. Nếu các vật phẩm này được làm thủ tục Hành lý ký gửi, khách hàng đồng ý chịu mọi rủi ro vận chuyển. Các vật phẩm này bao gồm tiền, nữ trang, kim loại quý hiếm, đồ dùng bằng bạc, đồ điện tử, máy vi tính, máy ảnh, máy quay phim, giấy tờ có thể chuyển nhượng, chứng khoán, các giấy tờ có giá trị khác, hộ chiếu và giấy tờ tùy thân.\r\nQuyền lục soát: Vì các lý do an toàn và an ninh, chúng tôi có thể yêu cầu quý khách và hành lý phải qua kiểm soát, soi chiếu bằng X-quang hoặc các hình thức soi chiếu khác. Chúng tôi có quyền kiểm tra vắng mặt hành lý của quý khách, nếu không tìm được quý khách, nhằm mục đích kiểm tra xem quý khách có hoặc hành lý của quý khách có chứa hàng hóa cấm hoặc không được chấp thuận.Nếu quý khách từ chối việc kiểm tra hoặc soi chiếu như vậy, chúng tôi có quyền từ chối vận chuyển quý khách và hành lý của quý khách mà không hoàn trả lại cước vận chuyển và không chịu trách nhiệm gì khác với quý khách.Trong trường hợp việc kiểm tra, soi chiếu gây ra thương tích cho quý khách hoặc tổn thất cho hành lý, chúng tôi không chịu trách nhiệm cho thương tích hoặc tổn thất đó, nếu không phải do lỗi hoặc sơ suất của chúng tôi.\r\nHành lý ký gửi: Sau khi hành lý được bàn giao cho chúng tôi để kiểm tra, chúng tôi sẽ bảo quản hành lý đó và phát hành một thẻ Hành lý cho mỗi kiện hành lý. Hành lý ký gửi phải có tên quý khách hoặc các có nhận dạng cá nhân được gắn một cách an toàn trên đó. Hành lý ký gửi được vận chuyển trên cùng tàu bay với quý khách, trừ khi chúng tôi quyết định vận chuyển hành lý đó trên chuyến bay khác do các lý do an toàn, an ninh hoặc khai thác. Nếu hành lý của quý khách được vận chuyển trên chuyến bay sau, chúng tôi sẽ giao hành lý đó cho quý khách trong một khoảng thời gian hợp lý sau khi chuyến bay đó đến, trừ khi quý khách bắt buộc phải có mặt để làm thủ tục hải quan theo luật định.\r\nHành lý ký gửi: Một khoản phí hành lý được tính cho việc vận chuyển Hành lý ký gửi. Mỗi hành khách chỉ được mua duy nhất một gói Hành ký ký gửi. Hành khách có thể mua các gói Hành lý tiêu chuẩn 20kg, 30kg, 40kg, 50kg, 60kg, 70kg, 80kg, 90kg,100kg (tùy theo hành trình bay), các gói Hành lý quá khổ 20kg, 30kg (hành khách có thể nâng hạn mức lên gói lớn hơn trước 3 tiếng so với giờ bay khởi hành dự kiến). Hành khách nào ký gửi hành lý vượt quá hạn mức hành lý đã mua khi đặt chỗ sẽ phải trả thêm phí tính theo từng kg tại quầy thủ tục đăng ký chuyến bay ở sân bay. Xin tham khảo thêm Biểu Phí của chúng tôi để có thêm chi tiết về mọi mức cước phí. Phí hành lý không được hoàn lại và không được chuyển nhượng.\r\nGiao nhận hành lý: Quý khách sẽ nhận hành lý ngay khi hành lý được vận chuyển đến điểm đến. Nếu quý khách không nhận hành lý trong khoảng thời gian hợp lý và chúng tôi phải lưu giữ hành lý, chúng tôi có thể tính phí kho bãi.Nếu quý khách không nhận hành lý ký gởi của mình trong vòng 2 tháng, chúng tôi sẽ có thể vứt bỏ hành lý đó mà không phải chịu bất kỳ trách nhiệm nào với quý khách.Chỉ người có thẻ hành lý đã được cấp cho hành khách khi làm thủ tục hành lý mới được quyền nhận hành lý. Nếu người nhận hành lý không xuất trình được thẻ hành lý, chúng tôi sẽ chỉ giao hành lý cho người đó, nếu người đó chứng minh được với chúng tôi về quyền với hành lý đó, và nếu chúng tôi có yêu cầu thì người đó phải cung cấp đảm bảo thích hợp để bồi hoàn cho chúng tôi mọi mất mát, thiệt hại hoặc chi phí mà chúng tôi có thể phải chịu do việc bàn giao hành lý đó. Việc người giữ thẻ hành lý chấp nhận hành lý tại thời điểm bàn giao là chứng cứ hiển nhiên cho việc hành lý đã được bàn giao trong điều kiện tốt và phù hợp với hợp đồng vận chuyển với chúng tôi.', 'https://storage.googleapis.com/airline-tickets-52c6e.firebasestorage.app/users/Quy định về hành lý/8ef8f984-8e77-4652-9325-cbaeec8c886e_quydinhhanhly1-1607067787431.jpg', '2025-05-03 10:11:49');
